    if (ext === "pdf") {
      rawText = await extractTextFromPdf(arrayBuffer);
    } else if (ext === "docx" || ext === "doc") {
      rawText = await extractTextFromDocx(arrayBuffer);
    } else {
      throw new Error(`Unsupported file type: .${ext}. Please upload a .pdf or .docx file.`);
    }
